import sys

class Solution:
    def solve(self, a, b) -> int:
        if a < 0: a = -a
        if b < 0: b = -b
        while b:
            a, b = b, a % b
        return abs(a)

if __name__ == '__main__':
    a, b = map(int, input().split())
    print(Solution().solve(a, b))
