#include <iostream>

class Solution {
public:
    int solve(int a, int b) {
        if (a < 0) a = -a;
        if (b < 0) b = -b;
        while (b) {
            int temp = a;
            a = b;
            b = temp % b;
        }
        return abs(a);
    }
};

test(int a[], int b[], int size) {
    Solution s;
    for (int i = 0; i < size; i++) {
        std::cout << s.solve(a[i], b[i]) << ' ';
    }
    std::cout << std::endl;
}

test(-10, -15, 1);
test(12, 18, 1);
```
